import { db } from "../firebase.config.ts";
import {
  collection,
  addDoc,
  getDocs,
  query,
  where,
  serverTimestamp,
} from "firebase/firestore";

// Firestore Collection: "courses"
// Document ID: auto-generated

export interface CourseDocument {
  title: string;          // required
  provider: string;       // default: ''
  category: string;       // default: ''
  duration: string;       // default: ''
  lessons: number;        // default: 0
  rating: number;         // default: 0.0
  reviewsCount: number;   // default: 0
  skillsCovered: string[];// default: []
  isFree: boolean;        // default: true
  url: string;            // default: ''
  isActive: boolean;      // default: true
  level: string;          // 'Beginner' | 'Intermediate' | 'Advanced'
  language: string;       // default: 'English'
  accessibilityFeatures: string[]; // e.g. ['Sign Language', 'Subtitles', 'Screen Reader']
  pwdFocused: boolean;    // true = specifically designed for PwD
  createdAt: any;         // serverTimestamp()
}

// Add a course (Admin only)
export const addCourse = async (courseData: Omit<CourseDocument, "createdAt">) => {
  const coursesRef = collection(db, "courses");
  await addDoc(coursesRef, { ...courseData, createdAt: serverTimestamp() });
};

// Get all active courses (public read)
export const getActiveCourses = async () => {
  const coursesRef = collection(db, "courses");
  const q = query(coursesRef, where("isActive", "==", true));
  const snap = await getDocs(q);
  return snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as CourseDocument & { id: string }));
};

// Get PwD-focused free courses only
export const getPwdFreeCourses = async () => {
  const coursesRef = collection(db, "courses");
  const q = query(
    coursesRef,
    where("isActive", "==", true),
    where("isFree", "==", true),
    where("pwdFocused", "==", true)
  );
  const snap = await getDocs(q);
  return snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as CourseDocument & { id: string }));
};

