// ── Seed Function ─────────────────────────────────────────────────────────────
// Run this ONCE to populate Firestore with all free PwD courses
// e.g., call seedCourses() from an admin page or a one-time script
export const seedCourses = async () => {
  const coursesRef = collection(db, "courses");
  const results = await Promise.allSettled(
    pwdFreeCourses.map((course) =>
      addDoc(coursesRef, { ...course, createdAt: serverTimestamp() })
    )
  );

  const succeeded = results.filter((r) => r.status === "fulfilled").length;
  const failed = results.filter((r) => r.status === "rejected").length;

  console.log(`✅ Seeded ${succeeded} courses successfully.`);
  if (failed > 0) console.warn(`⚠️ ${failed} courses failed to seed.`);
};